/**
 * background-bundle.js
 *
 * Single-file classic script — safe for importScripts() in both
 * Chrome MV3 and Firefox MV3 service workers.
 *
 * Contains (in order):
 *   1. engine.js  (sets globalThis.CCEngine)
 *   2. keystore.js (sets globalThis.CCKeystore, reads CCEngine)
 *   3. Background message handler
 *
 * Generated by: node build.js
 * Or edit this file directly for development.
 */

/* ═══════════════════════════════════════════════════════════════════════════
   PART 1: CRYPTO ENGINE
═══════════════════════════════════════════════════════════════════════════ */

(function () {

function buf2b64(buf) {
  const bytes = new Uint8Array(buf);
  let bin = '';
  for (let i = 0; i < bytes.length; i++) bin += String.fromCharCode(bytes[i]);
  return btoa(bin);
}
function b642buf(str) {
  const bin = atob(str);
  const buf = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) buf[i] = bin.charCodeAt(i);
  return buf.buffer;
}
function str2buf(str) { return new TextEncoder().encode(str).buffer; }
function buf2str(buf) { return new TextDecoder().decode(buf); }
function buf2hex(buf) {
  return Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2,'0')).join('');
}

const ALGO_ECDH = { name: 'ECDH', namedCurve: 'P-256' };
const ALGO_AES  = { name: 'AES-GCM', length: 256 };
const ALGO_WRAP = { name: 'AES-KW',  length: 256 };

async function generateIdentityKeypair() {
  return crypto.subtle.generateKey(ALGO_ECDH, true, ['deriveKey', 'deriveBits']);
}
async function exportPublicKey(key) {
  return buf2b64(await crypto.subtle.exportKey('spki', key));
}
async function exportPrivateKey(key) {
  return buf2b64(await crypto.subtle.exportKey('pkcs8', key));
}
async function importPublicKey(b64, namedCurve) {
  return crypto.subtle.importKey(
    'spki', b642buf(b64),
    { name: 'ECDH', namedCurve: namedCurve || 'P-256' },
    true, []
  );
}
async function importPrivateKey(b64) {
  return crypto.subtle.importKey(
    'pkcs8', b642buf(b64), ALGO_ECDH, true, ['deriveKey', 'deriveBits']
  );
}
async function deriveSharedKey(ourPriv, theirPub) {
  return crypto.subtle.deriveKey(
    { name: 'ECDH', public: theirPub }, ourPriv, ALGO_AES, false, ['encrypt', 'decrypt']
  );
}
async function keyFingerprint(b64) {
  return buf2hex(await crypto.subtle.digest('SHA-256', b642buf(b64)));
}

/* ── 1:1 wire format ──────────────────────────────────────────────────── */
const WIRE_REGEX = /^CRYPTOCHAT_V1:([A-Za-z0-9+/=]+):([A-Za-z0-9+/=]+):([A-Za-z0-9+/=]+)$/;
async function encryptMessage(plain, sharedKey, senderPubB64) {
  const iv  = crypto.getRandomValues(new Uint8Array(12));
  const enc = await crypto.subtle.encrypt({ name:'AES-GCM', iv }, sharedKey, str2buf(plain));
  return ['CRYPTOCHAT_V1', buf2b64(iv.buffer), buf2b64(enc), senderPubB64].join(':');
}
async function decryptMessage(wire, sharedKey) {
  const m = wire.match(WIRE_REGEX);
  if (!m) throw new Error('Not a valid CryptoChat V1 message');
  const [, ivB64, cipB64, senderPubKeyB64] = m;
  const plain = await crypto.subtle.decrypt(
    { name:'AES-GCM', iv: new Uint8Array(b642buf(ivB64)) }, sharedKey, b642buf(cipB64)
  );
  return { plaintext: buf2str(plain), senderPubKeyB64 };
}
function isV1Message(t) { return typeof t === 'string' && WIRE_REGEX.test(t.trim()); }

/* ── Group wire format ────────────────────────────────────────────────── */
const GRP_REGEX = /^CRYPTOCHAT_GRP_V1:([A-Za-z0-9+/=]+):([A-Za-z0-9+/=]+):([A-Za-z0-9+/=]+):([A-Za-z0-9+/=]+)$/;

async function encryptGroupMessage(plain, senderPubB64, senderPriv, recipients) {
  const dek = await crypto.subtle.generateKey({ name:'AES-GCM', length:256 }, true, ['encrypt','decrypt','wrapKey','unwrapKey']);
  const iv  = crypto.getRandomValues(new Uint8Array(12));
  const body = await crypto.subtle.encrypt({ name:'AES-GCM', iv }, dek, str2buf(plain));

  const slots = [];
  for (const r of recipients) {
    try {
      const pub   = await importPublicKey(r.publicKeyB64, r.curve);
      const wkey  = await crypto.subtle.deriveKey(
        { name:'ECDH', public: pub }, senderPriv, ALGO_WRAP, false, ['wrapKey','unwrapKey']
      );
      const wdek  = await crypto.subtle.wrapKey('raw', dek, wkey, { name:'AES-KW' });
      slots.push({ h: r.handle, p: r.publicKeyB64, dek: buf2b64(wdek) });
    } catch(e) { console.warn('[CCBg] skip recipient', r.handle, e.message); }
  }
  if (!slots.length) throw new Error('No valid recipients');

  const msgIdBuf = await crypto.subtle.digest('SHA-256', str2buf(buf2b64(body) + Date.now()));
  const msgId    = buf2b64(msgIdBuf.slice(0, 8));
  const slotsB64 = buf2b64(str2buf(JSON.stringify(slots)));
  return ['CRYPTOCHAT_GRP_V1', msgId, buf2b64(iv.buffer), buf2b64(body), slotsB64].join(':');
}

async function decryptGroupMessage(wire, ourPubB64, ourPriv, senderPubB64) {
  const m = wire.match(GRP_REGEX);
  if (!m) throw new Error('Not a valid group message');
  const [, , ivB64, bodyB64, slotsB64] = m;
  const slots = JSON.parse(buf2str(b642buf(slotsB64)));
  const mySlot = slots.find(s => s.p === ourPubB64);
  if (!mySlot) throw new Error('No slot for your key in this group message');
  const senderPub = await importPublicKey(senderPubB64);
  const wkey = await crypto.subtle.deriveKey(
    { name:'ECDH', public: senderPub }, ourPriv, ALGO_WRAP, false, ['wrapKey','unwrapKey']
  );
  const dek = await crypto.subtle.unwrapKey('raw', b642buf(mySlot.dek), wkey, { name:'AES-KW' }, ALGO_AES, false, ['encrypt','decrypt']);
  const plain = await crypto.subtle.decrypt(
    { name:'AES-GCM', iv: new Uint8Array(b642buf(ivB64)) }, dek, b642buf(bodyB64)
  );
  return { plaintext: buf2str(plain), slotCount: slots.length, recipientHandles: slots.map(s=>s.h), senderPubKeyB64: senderPubB64 };
}
function isGroupMessage(t) { return typeof t === 'string' && GRP_REGEX.test(t.trim()); }

/* ── GPG parser ───────────────────────────────────────────────────────── */
const OID_MAP = {
  '2a8648ce3d030107':    { curve:'P-256',  subtle:true  },
  '2b81040022':          { curve:'P-384',  subtle:true  },
  '2b81040023':          { curve:'P-521',  subtle:true  },
  '2b060104019755010501':{ curve:'X25519', subtle:false },
  '2b06010401da470f01':  { curve:'Ed25519',subtle:false },
};

function dearmor(armored) {
  const lines = armored.replace(/\r\n/g,'\n').split('\n');
  const b64 = [];
  let inBody = false;
  for (const line of lines) {
    if (line.startsWith('-----BEGIN')) { inBody = true; continue; }
    if (line.startsWith('-----END'))   break;
    if (!inBody || line.startsWith('=') || line.trim() === '') continue;
    if (/^[A-Za-z0-9+/=]+$/.test(line.trim())) b64.push(line.trim());
  }
  return b642buf(b64.join(''));
}

function readMPI(view, off) {
  const bits = view.getUint16(off); off += 2;
  const byteLen = Math.ceil(bits/8);
  return { bytes: new Uint8Array(view.buffer, view.byteOffset+off, byteLen), next: off+byteLen };
}

const SPKI_HDR = {
  'P-256': new Uint8Array([0x30,0x59,0x30,0x13,0x06,0x07,0x2a,0x86,0x48,0xce,0x3d,0x02,0x01,0x06,0x08,0x2a,0x86,0x48,0xce,0x3d,0x03,0x01,0x07,0x03,0x42,0x00]),
  'P-384': new Uint8Array([0x30,0x76,0x30,0x10,0x06,0x07,0x2a,0x86,0x48,0xce,0x3d,0x02,0x01,0x06,0x05,0x2b,0x81,0x04,0x00,0x22,0x03,0x62,0x00]),
  'P-521': new Uint8Array([0x30,0x81,0x9b,0x30,0x10,0x06,0x07,0x2a,0x86,0x48,0xce,0x3d,0x02,0x01,0x06,0x05,0x2b,0x81,0x04,0x00,0x23,0x03,0x86,0x00]),
};

function buildEcSpki(curve, point) {
  const hdr = SPKI_HDR[curve]; if (!hdr) return null;
  const p = point[0] === 0x40 ? new Uint8Array([0x04,...point.slice(1)]) : point;
  const out = new Uint8Array(hdr.length + p.length);
  out.set(hdr); out.set(p, hdr.length);
  return out.buffer;
}

function parsePgpPkt(buf) {
  const v = new DataView(buf); let off = 0;
  const ver = v.getUint8(off++); off += 4;
  const algo = v.getUint8(off++);
  if (algo === 18 || algo === 22 || algo === 19) {
    const olen = v.getUint8(off++);
    const obytes = new Uint8Array(buf, off, olen); off += olen;
    const ohex = Array.from(obytes).map(b=>b.toString(16).padStart(2,'0')).join('');
    const ci = OID_MAP[ohex];
    if (!ci) return { type:'unsupported', reason:`Unknown OID ${ohex}` };
    if (!ci.subtle) return { type:'unsupported', reason:`${ci.curve} not bridged to SubtleCrypto` };
    const mpi = readMPI(v, off);
    const spki = buildEcSpki(ci.curve, mpi.bytes);
    if (!spki) return { type:'unsupported', reason:'SPKI build failed' };
    return { type:'ecdh', curve: ci.curve, publicKeyB64: buf2b64(spki) };
  }
  if (algo === 1 || algo === 17) return { type:'rsa' };
  return { type:'unsupported', reason:`algo ${algo}` };
}

async function parseGpgPublicKey(armored) {
  try {
    const raw = dearmor(armored); const bytes = new Uint8Array(raw);
    let off = 0; const pkts = [];
    while (off < bytes.length) {
      const tag = bytes[off++]; if (!(tag & 0x80)) break;
      let ptag, len;
      if (tag & 0x40) {
        ptag = tag & 0x3f;
        const fo = bytes[off++];
        if (fo < 192) len = fo;
        else if (fo < 224) { len = ((fo-192)<<8)+bytes[off++]+192; }
        else if (fo===255) { len=(bytes[off]<<24)|(bytes[off+1]<<16)|(bytes[off+2]<<8)|bytes[off+3]; off+=4; }
        else break;
      } else {
        ptag = (tag & 0x3c)>>2;
        const lt = tag & 0x03;
        if (lt===0) len=bytes[off++];
        else if (lt===1) { len=(bytes[off++]<<8)|bytes[off++]; }
        else if (lt===2) { len=(bytes[off++]<<24)|(bytes[off++]<<16)|(bytes[off++]<<8)|bytes[off++]; }
        else len=bytes.length-off;
      }
      pkts.push({ tag: ptag, body: raw.slice(off, off+len) });
      off += len;
    }
    const pub = pkts.find(p=>p.tag===14) || pkts.find(p=>p.tag===6);
    if (!pub) return { error:'No public key packet' };
    const ki = parsePgpPkt(pub.body);
    const uidPkt = pkts.find(p=>p.tag===13);
    const uid = uidPkt ? buf2str(uidPkt.body) : null;
    const fp = buf2hex(await crypto.subtle.digest('SHA-256', pub.body));
    if (ki.type === 'ecdh') {
      return { type:'ecdh', curve:ki.curve, publicKeyB64:ki.publicKeyB64,
               fingerprint:fp, shortFingerprint:fp.slice(-16).toUpperCase(), uid, source:'gpg' };
    }
    if (ki.type === 'rsa') {
      return { type:'rsa', publicArmor:armored, fingerprint:fp,
               shortFingerprint:fp.slice(-16).toUpperCase(), uid, source:'gpg',
               error:'RSA GPG key stored — encryption via openpgp.js bridge (coming soon)' };
    }
    return { error: ki.reason || 'Unsupported', source:'gpg' };
  } catch(e) { return { error:`GPG parse: ${e.message}` }; }
}

function isGpgArmor(t) {
  return typeof t==='string' && t.includes('-----BEGIN PGP PUBLIC KEY BLOCK-----');
}

/* ════════════════════════════════════════════════════════════════════════════
   HYBRID PQC ENGINE — ECDH P-256 + ML-KEM-768
   Wire format V2:
   CRYPTOCHAT_V2:<b64_iv>:<b64_body>:<b64_ecdhPub>:<b64_mlkemCt>:<b64_mlkemPub>

   Key agreement:
     1. ECDH P-256  → ecdhSecret (32 bytes, raw bits)
     2. ML-KEM-768  → mlkemSecret (32 bytes, shared secret)
     3. HKDF-SHA256(ecdhSecret || mlkemSecret) → AES-256-GCM key

   An attacker must break BOTH primitives to recover the message.
   ECDH provides classical security; ML-KEM provides quantum resistance.

   Availability:
     PQC is enabled when globalThis.MLKEM768 is set (real bundle loaded).
     When only the stub is present (MLKEM768 === null), falls back to V1.
════════════════════════════════════════════════════════════════════════════ */

const V2_REGEX = /^CRYPTOCHAT_V2:([A-Za-z0-9+/=]+):([A-Za-z0-9+/=]+):([A-Za-z0-9+/=]+):([A-Za-z0-9+/=]+):([A-Za-z0-9+/=]+)$/;

function isPqcAvailable() {
  return !!(globalThis.MLKEM768?.MlKem768);
}

/**
 * Generate an ML-KEM-768 keypair.
 * Returns { mlkemPk: Uint8Array(1184), mlkemSk: Uint8Array(2400) }
 */
async function mlkemGenerateKeypair() {
  const kem = new globalThis.MLKEM768.MlKem768();
  const [pk, sk] = await kem.generateKeyPair();
  return { mlkemPk: pk, mlkemSk: sk };
}

/**
 * HKDF-SHA256: derive a 32-byte key from input key material.
 * ikm: Uint8Array, info: string label
 */
async function hkdf32(ikm, info) {
  const baseKey = await crypto.subtle.importKey(
    'raw', ikm, 'HKDF', false, ['deriveKey']
  );
  const derived = await crypto.subtle.deriveKey(
    {
      name: 'HKDF',
      hash: 'SHA-256',
      salt: new Uint8Array(32), // zero salt — both parties compute same value
      info: str2buf(info),
    },
    baseKey,
    { name: 'AES-GCM', length: 256 },
    false,
    ['encrypt', 'decrypt']
  );
  return derived;
}

/**
 * Derive ECDH shared secret as raw bytes (32 bytes for P-256).
 */
async function deriveEcdhBits(ourPriv, theirPub) {
  const bits = await crypto.subtle.deriveBits(
    { name: 'ECDH', public: theirPub },
    ourPriv,
    256
  );
  return new Uint8Array(bits);
}

/**
 * Encrypt with V2 hybrid scheme.
 *
 * @param {string}   plaintext
 * @param {string}   senderEcdhPubB64    — our ECDH public key (for recipient lookup)
 * @param {CryptoKey} senderEcdhPriv     — our ECDH private key
 * @param {string}   recipientEcdhPubB64 — their ECDH public key
 * @param {Uint8Array} recipientMlkemPk  — their ML-KEM-768 public key (1184 bytes)
 * @returns {string} V2 wire string
 */
async function encryptMessageV2(plaintext, senderEcdhPubB64, senderEcdhPriv, recipientEcdhPubB64, recipientMlkemPk) {
  // 1. ECDH shared secret
  const recipientEcdhPub = await importPublicKey(recipientEcdhPubB64);
  const ecdhSecret = await deriveEcdhBits(senderEcdhPriv, recipientEcdhPub);

  // 2. ML-KEM encapsulation — sender encaps to recipient's public key
  const kem = new globalThis.MLKEM768.MlKem768();
  const [mlkemCt, mlkemSecret] = await kem.encap(recipientMlkemPk);

  // 3. Combine secrets via HKDF: H(ecdhSecret || mlkemSecret)
  const combined = new Uint8Array(ecdhSecret.length + mlkemSecret.length);
  combined.set(ecdhSecret);
  combined.set(mlkemSecret, ecdhSecret.length);
  const hybridKey = await hkdf32(combined, 'CryptoChat-V2-hybrid-key');

  // 4. Encrypt with AES-256-GCM
  const iv = crypto.getRandomValues(new Uint8Array(12));
  const bodyBuf = await crypto.subtle.encrypt(
    { name: 'AES-GCM', iv },
    hybridKey,
    str2buf(plaintext)
  );

  return [
    'CRYPTOCHAT_V2',
    buf2b64(iv.buffer),
    buf2b64(bodyBuf),
    senderEcdhPubB64,           // so recipient knows whose ECDH key to use
    buf2b64(mlkemCt.buffer),    // ML-KEM ciphertext (1088 bytes)
    buf2b64(recipientMlkemPk.buffer), // recipient's ML-KEM pubkey (for verification)
  ].join(':');
}

/**
 * Decrypt a V2 hybrid message.
 *
 * @param {string}    wireText
 * @param {CryptoKey} recipientEcdhPriv  — our ECDH private key
 * @param {string}    senderEcdhPubB64   — sender's ECDH public key (from contacts)
 * @param {Uint8Array} recipientMlkemSk  — our ML-KEM-768 secret key (2400 bytes)
 * @returns {{ plaintext: string, senderEcdhPubB64: string }}
 */
async function decryptMessageV2(wireText, recipientEcdhPriv, senderEcdhPubB64, recipientMlkemSk) {
  const m = wireText.match(V2_REGEX);
  if (!m) throw new Error('Not a valid CryptoChat V2 message');

  const [, ivB64, bodyB64, embeddedSenderPub, mlkemCtB64] = m;

  // 1. ECDH shared secret (us ← sender)
  const senderEcdhPub = await importPublicKey(senderEcdhPubB64 || embeddedSenderPub);
  const ecdhSecret = await deriveEcdhBits(recipientEcdhPriv, senderEcdhPub);

  // 2. ML-KEM decapsulation
  const mlkemCt = new Uint8Array(b642buf(mlkemCtB64));
  const kem = new globalThis.MLKEM768.MlKem768();
  const mlkemSecret = await kem.decap(mlkemCt, recipientMlkemSk);

  // 3. Reconstruct hybrid key via HKDF
  const combined = new Uint8Array(ecdhSecret.length + mlkemSecret.length);
  combined.set(ecdhSecret);
  combined.set(mlkemSecret, ecdhSecret.length);
  const hybridKey = await hkdf32(combined, 'CryptoChat-V2-hybrid-key');

  // 4. Decrypt
  const plainBuf = await crypto.subtle.decrypt(
    { name: 'AES-GCM', iv: new Uint8Array(b642buf(ivB64)) },
    hybridKey,
    b642buf(bodyB64)
  );

  return { plaintext: buf2str(plainBuf), senderEcdhPubB64: embeddedSenderPub };
}

function isV2Message(t) {
  return typeof t === 'string' && V2_REGEX.test(t.trim());
}

/**
 * Group V2 — same DEK approach as V1 group but uses hybrid key for each slot.
 * Body is AES-256-GCM with a random DEK.
 * Each slot encrypts the DEK using V2 hybrid ECDH+ML-KEM key agreement.
 *
 * Wire format:
 * CRYPTOCHAT_GRPV2:<msgId>:<iv>:<body>:<slotsB64>
 * Each slot: { h, ecdhPub, mlkemCt, wrappedDek }
 */
const GRP2_REGEX = /^CRYPTOCHAT_GRPV2:([A-Za-z0-9+/=]+):([A-Za-z0-9+/=]+):([A-Za-z0-9+/=]+):([A-Za-z0-9+/=]+)$/;

async function encryptGroupMessageV2(plaintext, senderEcdhPubB64, senderEcdhPriv, recipients) {
  // recipients: [{ handle, ecdhPubB64, mlkemPkB64 }]

  // 1. Random DEK for the body
  const dek = await crypto.subtle.generateKey(
    { name: 'AES-GCM', length: 256 }, true, ['encrypt', 'decrypt', 'wrapKey', 'unwrapKey']
  );
  const iv = crypto.getRandomValues(new Uint8Array(12));
  const bodyBuf = await crypto.subtle.encrypt({ name: 'AES-GCM', iv }, dek, str2buf(plaintext));

  // 2. For each recipient, derive a hybrid key and wrap the DEK with it
  const slots = [];
  for (const r of recipients) {
    try {
      const recipientEcdhPub = await importPublicKey(r.ecdhPubB64);
      const ecdhSecret = await deriveEcdhBits(senderEcdhPriv, recipientEcdhPub);

      const kem = new globalThis.MLKEM768.MlKem768();
      const mlkemPk = new Uint8Array(b642buf(r.mlkemPkB64));
      const [mlkemCt, mlkemSecret] = await kem.encap(mlkemPk);

      const combined = new Uint8Array(ecdhSecret.length + mlkemSecret.length);
      combined.set(ecdhSecret); combined.set(mlkemSecret, ecdhSecret.length);

      // Use hybrid key as AES-KW wrapping key
      const wrapKeyMat = await hkdf32(combined, 'CryptoChat-V2-wrap-key');
      // Re-derive as AES-KW key
      const rawKey = await crypto.subtle.exportKey('raw', wrapKeyMat);
      const wrapKey = await crypto.subtle.importKey('raw', rawKey, { name: 'AES-KW', length: 256 }, false, ['wrapKey']);

      const wrappedDek = await crypto.subtle.wrapKey('raw', dek, wrapKey, { name: 'AES-KW' });

      slots.push({
        h:          r.handle,
        ecdhPub:    r.ecdhPubB64,
        mlkemCt:    buf2b64(mlkemCt.buffer),
        wrappedDek: buf2b64(wrappedDek),
      });
    } catch (e) {
      console.warn('[CC PQC] skip group recipient', r.handle, e.message);
    }
  }

  if (!slots.length) throw new Error('No valid recipients for V2 group message');

  const msgIdBuf = await crypto.subtle.digest('SHA-256', str2buf(buf2b64(bodyBuf) + Date.now()));
  const msgId = buf2b64(msgIdBuf.slice(0, 8));
  const slotsB64 = buf2b64(str2buf(JSON.stringify(slots)));

  return ['CRYPTOCHAT_GRPV2', msgId, buf2b64(iv.buffer), buf2b64(bodyBuf), slotsB64].join(':');
}

async function decryptGroupMessageV2(wireText, ourEcdhPubB64, ourEcdhPriv, ourMlkemSkB64) {
  const m = wireText.match(GRP2_REGEX);
  if (!m) throw new Error('Not a valid V2 group message');
  const [, , ivB64, bodyB64, slotsB64] = m;
  const slots = JSON.parse(buf2str(b642buf(slotsB64)));

  const mySlot = slots.find(s => s.ecdhPub === ourEcdhPubB64);
  if (!mySlot) throw new Error('No slot for your key in this group message');

  // Reconstruct hybrid key from our private keys
  // We need the SENDER'S ECDH public key — it's not in the slot, it's embedded per-sender.
  // For group V2, the sender's ECDH pub is recoverable from the slot's mlkemCt approach:
  // Actually in group V2 we don't store sender pub per slot.
  // Use: ECDH between recipient private and sender public (sender pub needed from contacts).
  // For simplicity in group V2, we store sender's ECDH pub in the slot too:
  // This is already handled — slots include 'ecdhPub' = RECIPIENT'S pub.
  // We need to derive the same secret the sender used.
  // The sender used: ECDH(senderPriv, recipientPub) + MLKEM.encap(recipientMlkemPk)
  // We compute: ECDH(recipientPriv, senderPub) + MLKEM.decap(mlkemCt, recipientMlkemSk)
  // But we need the sender's ECDH pub... add it to slot:
  throw new Error('Group V2 decrypt requires sender ECDH pub — use decryptGroupMessageV2WithSender');
}

async function decryptGroupMessageV2WithSender(wireText, ourEcdhPubB64, ourEcdhPriv, ourMlkemSkB64, senderEcdhPubB64) {
  const m = wireText.match(GRP2_REGEX);
  if (!m) throw new Error('Not a valid V2 group message');
  const [, , ivB64, bodyB64, slotsB64] = m;
  const slots = JSON.parse(buf2str(b642buf(slotsB64)));

  const mySlot = slots.find(s => s.ecdhPub === ourEcdhPubB64);
  if (!mySlot) throw new Error('No slot for your key in this group message');

  // Reconstruct hybrid key
  const senderEcdhPub = await importPublicKey(senderEcdhPubB64);
  const ecdhSecret    = await deriveEcdhBits(ourEcdhPriv, senderEcdhPub);

  const mlkemCt = new Uint8Array(b642buf(mySlot.mlkemCt));
  const mlkemSk = new Uint8Array(b642buf(ourMlkemSkB64));
  const kem = new globalThis.MLKEM768.MlKem768();
  const mlkemSecret = await kem.decap(mlkemCt, mlkemSk);

  const combined = new Uint8Array(ecdhSecret.length + mlkemSecret.length);
  combined.set(ecdhSecret); combined.set(mlkemSecret, ecdhSecret.length);

  const wrapKeyMat = await hkdf32(combined, 'CryptoChat-V2-wrap-key');
  const rawKey = await crypto.subtle.exportKey('raw', wrapKeyMat);
  const wrapKey = await crypto.subtle.importKey('raw', rawKey, { name: 'AES-KW', length: 256 }, false, ['unwrapKey']);

  const dek = await crypto.subtle.unwrapKey(
    'raw', b642buf(mySlot.wrappedDek), wrapKey,
    { name: 'AES-KW' }, { name: 'AES-GCM', length: 256 }, false, ['decrypt']
  );

  const plain = await crypto.subtle.decrypt(
    { name: 'AES-GCM', iv: new Uint8Array(b642buf(ivB64)) },
    dek, b642buf(bodyB64)
  );

  return {
    plaintext:         buf2str(plain),
    slotCount:         slots.length,
    recipientHandles:  slots.map(s => s.h),
    senderEcdhPubB64,
  };
}

function isV2GroupMessage(t) {
  return typeof t === 'string' && GRP2_REGEX.test(t.trim());
}

globalThis.CCEngine = {
  // Classical ECDH
  generateIdentityKeypair, exportPublicKey, exportPrivateKey,
  importPublicKey, importPrivateKey, deriveSharedKey, keyFingerprint,
  // V1 messages
  encryptMessage, decryptMessage, isV1Message,
  // V1 group
  encryptGroupMessage, decryptGroupMessage, isGroupMessage,
  // GPG
  parseGpgPublicKey, isGpgArmor,
  // PQC / hybrid V2
  isPqcAvailable, mlkemGenerateKeypair,
  encryptMessageV2, decryptMessageV2, isV2Message,
  encryptGroupMessageV2, decryptGroupMessageV2WithSender, isV2GroupMessage,
  // Encoding utils
  buf2b64, b642buf, buf2str, str2buf,
};

})(); // end engine IIFE

/* ═══════════════════════════════════════════════════════════════════════════
   PART 2: KEY STORE
═══════════════════════════════════════════════════════════════════════════ */

(function () {
  const E = globalThis.CCEngine;
  const K_ID = 'cc_identity_v2', K_CT = 'cc_contacts_v2';

  function sGet(k)   { return new Promise(r=>chrome.storage.local.get(k, x=>r(x[k]??null))); }
  function sSet(k,v) { return new Promise(r=>chrome.storage.local.set({[k]:v},r)); }
  function sDel(k)   { return new Promise(r=>chrome.storage.local.remove(k,r)); }

  async function getOrCreateIdentity() {
    const s = await sGet(K_ID);
    if (s) {
      return {
        publicKey:      await E.importPublicKey(s.publicKeyB64),
        privateKey:     await E.importPrivateKey(s.privateKeyB64),
        publicKeyB64:   s.publicKeyB64,
        fingerprint:    s.fingerprint,
        // ML-KEM keys (may be null if generated before PQC was available)
        mlkemPkB64:     s.mlkemPkB64  || null,
        mlkemSkB64:     s.mlkemSkB64  || null,
        pqcEnabled:     !!(s.mlkemPkB64),
      };
    }
    // First run — generate ECDH keypair
    const kp  = await E.generateIdentityKeypair();
    const pub  = await E.exportPublicKey(kp.publicKey);
    const pri  = await E.exportPrivateKey(kp.privateKey);
    const fp   = await E.keyFingerprint(pub);

    // Also generate ML-KEM-768 keypair if PQC is available
    let mlkemPkB64 = null, mlkemSkB64 = null;
    if (E.isPqcAvailable()) {
      const mk = await E.mlkemGenerateKeypair();
      mlkemPkB64 = E.buf2b64(mk.mlkemPk.buffer);
      mlkemSkB64 = E.buf2b64(mk.mlkemSk.buffer);
    }

    await sSet(K_ID, { publicKeyB64: pub, privateKeyB64: pri, fingerprint: fp, mlkemPkB64, mlkemSkB64 });
    return {
      publicKey: kp.publicKey, privateKey: kp.privateKey,
      publicKeyB64: pub, fingerprint: fp,
      mlkemPkB64, mlkemSkB64, pqcEnabled: !!(mlkemPkB64),
    };
  }

  /**
   * Upgrade an existing ECDH-only identity to add ML-KEM keys.
   * Called automatically when PQC bundle is first loaded.
   */
  async function upgradeIdentityToPqc() {
    if (!E.isPqcAvailable()) return { upgraded: false, reason: 'PQC bundle not loaded' };
    const s = await sGet(K_ID);
    if (!s) return { upgraded: false, reason: 'No identity yet' };
    if (s.mlkemPkB64) return { upgraded: false, reason: 'Already has ML-KEM keys' };

    const mk = await E.mlkemGenerateKeypair();
    s.mlkemPkB64 = E.buf2b64(mk.mlkemPk.buffer);
    s.mlkemSkB64 = E.buf2b64(mk.mlkemSk.buffer);
    await sSet(K_ID, s);
    return { upgraded: true, mlkemPkB64: s.mlkemPkB64 };
  }

  async function getPublicKeyB64() { const s=await sGet(K_ID); return s?s.publicKeyB64:null; }
  async function deleteIdentity() { await sDel(K_ID); }

  async function listContacts() { return (await sGet(K_CT)) || []; }

  async function saveContact(rec) {
    const contacts = await listContacts();
    const idx = contacts.findIndex(c=>c.handle===rec.handle&&c.platform===rec.platform);
    const full = {
      handle:rec.handle, platform:rec.platform, displayName:rec.displayName||rec.handle,
      publicKeyB64:rec.publicKeyB64||null, publicArmor:rec.publicArmor||null,
      source:rec.source||'native', curve:rec.curve||null,
      fingerprint:rec.fingerprint||null, uid:rec.uid||null,
      verified:rec.verified||false, addedAt:Date.now()
    };
    if (idx>=0) contacts[idx]={...contacts[idx],...full}; else contacts.push(full);
    await sSet(K_CT, contacts); return full;
  }

  async function deleteContact(h,p) {
    await sSet(K_CT, (await listContacts()).filter(c=>!(c.handle===h&&c.platform===p)));
  }
  async function verifyContact(h,p) {
    const ct=await listContacts(); const i=ct.findIndex(c=>c.handle===h&&c.platform===p);
    if(i>=0){ct[i].verified=true; await sSet(K_CT,ct);}
  }
  async function getContact(h,p) {
    return (await listContacts()).find(c=>c.handle===h&&c.platform===p)||null;
  }

  const _cache = new Map();
  async function getSharedKeyForContact(h,p) {
    const ck=`${p}:${h}`;
    if(_cache.has(ck)) return _cache.get(ck);
    const id=await getOrCreateIdentity(); const ct=await getContact(h,p);
    if(!ct||!ct.publicKeyB64) throw new Error(`No key for ${h} (${p})`);
    const pub=await E.importPublicKey(ct.publicKeyB64, ct.curve);
    const sk=await E.deriveSharedKey(id.privateKey,pub);
    _cache.set(ck,sk); return sk;
  }

  async function resolveGroupRecipients(handles) {
    const out=[];
    for(const {handle,platform} of handles) {
      const c=await getContact(handle,platform);
      if(c&&c.publicKeyB64) out.push({handle,platform,publicKeyB64:c.publicKeyB64,curve:c.curve});
    }
    return out;
  }

  globalThis.CCKeystore = {
    getOrCreateIdentity, getPublicKeyB64, deleteIdentity,
    upgradeIdentityToPqc,
    listContacts, saveContact, deleteContact, verifyContact,
    getContact, getSharedKeyForContact, resolveGroupRecipients,
  };
})(); // end keystore IIFE

/* ═══════════════════════════════════════════════════════════════════════════
   PART 3: BACKGROUND MESSAGE HANDLER
═══════════════════════════════════════════════════════════════════════════ */

(function () {
  const E  = globalThis.CCEngine;
  const KS = globalThis.CCKeystore;

  chrome.runtime.onMessage.addListener((msg, _sender, respond) => {
    handle(msg).then(respond).catch(err => respond({ error: err.message || String(err) }));
    return true;
  });

  // Auto-upgrade identity to add ML-KEM keys when PQC bundle first loads
  (async () => { try { await KS.upgradeIdentityToPqc(); } catch(_) {} })();

  async function handle(msg) {
    switch (msg.type) {

      /* ── Encrypt 1:1 (V2 if both have ML-KEM keys, else V1) ──────── */
      case 'ENCRYPT_MESSAGE': {
        const { plaintext, contactHandle, contactPlatform } = msg;
        if (!plaintext) return { error: 'No plaintext' };
        const id      = await KS.getOrCreateIdentity();
        const contact = await KS.getContact(contactHandle, contactPlatform);
        if (!contact?.publicKeyB64) return { error: `No key for ${contactHandle}` };

        if (E.isPqcAvailable() && id.mlkemPkB64 && contact.mlkemPkB64) {
          const ct = await E.encryptMessageV2(
            plaintext, id.publicKeyB64, id.privateKey,
            contact.publicKeyB64, new Uint8Array(E.b642buf(contact.mlkemPkB64))
          );
          return { ciphertext: ct, format: 'v2' };
        }
        const sk = await KS.getSharedKeyForContact(contactHandle, contactPlatform);
        const ct = await E.encryptMessage(plaintext, sk, id.publicKeyB64);
        return { ciphertext: ct, format: 'v1' };
      }

      /* ── Encrypt group ────────────────────────────────────────────── */
      case 'ENCRYPT_GROUP': {
        const { plaintext, recipients } = msg;
        if (!plaintext)          return { error: 'No plaintext' };
        if (!recipients?.length) return { error: 'No recipients' };
        const id = await KS.getOrCreateIdentity();

        const allRecip = [...recipients];
        if (!allRecip.find(r => r.publicKeyB64 === id.publicKeyB64)) {
          allRecip.push({ handle:'__self__', platform:'self', publicKeyB64:id.publicKeyB64, mlkemPkB64:id.mlkemPkB64||null });
        }
        const resolved = [];
        for (const r of allRecip) {
          if (r.publicKeyB64) { resolved.push(r); continue; }
          const c = await KS.getContact(r.handle, r.platform);
          if (c?.publicKeyB64) resolved.push({ ...r, publicKeyB64:c.publicKeyB64, mlkemPkB64:c.mlkemPkB64||null });
        }

        const allHavePqc = E.isPqcAvailable() && id.mlkemPkB64 && resolved.every(r=>r.mlkemPkB64);
        if (allHavePqc) {
          const v2r = resolved.map(r=>({ handle:r.handle, ecdhPubB64:r.publicKeyB64, mlkemPkB64:r.mlkemPkB64 }));
          const ct  = await E.encryptGroupMessageV2(plaintext, id.publicKeyB64, id.privateKey, v2r);
          return { ciphertext:ct, recipientCount:resolved.length, format:'v2-group' };
        }
        const ct = await E.encryptGroupMessage(plaintext, id.publicKeyB64, id.privateKey, resolved);
        return { ciphertext:ct, recipientCount:resolved.length, format:'v1-group' };
      }

      /* ── Decrypt (V2 group → V2 1:1 → V1 group → V1 1:1) ─────────── */
      case 'DECRYPT_MESSAGE': {
        const { wireText } = msg;
        if (!wireText) return { error: 'No ciphertext' };
        const id       = await KS.getOrCreateIdentity();
        const contacts = await KS.listContacts();

        if (E.isV2GroupMessage(wireText)) {
          if (!E.isPqcAvailable() || !id.mlkemSkB64)
            return { error: 'V2 (quantum-resistant) message — install the PQC bundle to decrypt.' };
          for (const c of contacts) {
            if (!c.publicKeyB64) continue;
            try {
              const r = await E.decryptGroupMessageV2WithSender(wireText, id.publicKeyB64, id.privateKey, id.mlkemSkB64, c.publicKeyB64);
              return { ...r, senderHandle:c.handle, senderPlatform:c.platform, senderVerified:c.verified, format:'v2-group' };
            } catch(_) {}
          }
          try {
            const r = await E.decryptGroupMessageV2WithSender(wireText, id.publicKeyB64, id.privateKey, id.mlkemSkB64, id.publicKeyB64);
            return { ...r, senderHandle:'(you)', format:'v2-group' };
          } catch(_) {}
          return { error: 'No matching key to decrypt this V2 group message' };
        }

        if (E.isV2Message(wireText)) {
          if (!E.isPqcAvailable() || !id.mlkemSkB64)
            return { error: 'V2 (quantum-resistant) message — install the PQC bundle to decrypt.' };
          const mlkemSk = new Uint8Array(E.b642buf(id.mlkemSkB64));
          for (const c of contacts) {
            if (!c.publicKeyB64) continue;
            try {
              const r = await E.decryptMessageV2(wireText, id.privateKey, c.publicKeyB64, mlkemSk);
              return { ...r, senderHandle:c.handle, senderPlatform:c.platform, senderVerified:c.verified, format:'v2' };
            } catch(_) {}
          }
          return { error: 'No matching key to decrypt this V2 message' };
        }

        if (E.isGroupMessage(wireText)) {
          for (const c of contacts) {
            if (!c.publicKeyB64) continue;
            try {
              const r = await E.decryptGroupMessage(wireText, id.publicKeyB64, id.privateKey, c.publicKeyB64);
              return { ...r, senderHandle:c.handle, senderPlatform:c.platform, senderVerified:c.verified, format:'group' };
            } catch(_) {}
          }
          try {
            const r = await E.decryptGroupMessage(wireText, id.publicKeyB64, id.privateKey, id.publicKeyB64);
            return { ...r, senderHandle:'(you)', format:'group' };
          } catch(_) {}
          return { error: 'No matching key to decrypt group message' };
        }

        if (E.isV1Message(wireText)) {
          for (const c of contacts) {
            if (!c.publicKeyB64) continue;
            try {
              const pub = await E.importPublicKey(c.publicKeyB64, c.curve);
              const sk  = await E.deriveSharedKey(id.privateKey, pub);
              const r   = await E.decryptMessage(wireText, sk);
              return { ...r, senderHandle:c.handle, senderPlatform:c.platform, senderVerified:c.verified, format:'v1' };
            } catch(_) {}
          }
          return { error: 'No key found — have you added the sender as a contact?' };
        }

        return { error: 'Unrecognized CryptoChat message format' };
      }

      /* ── GET_PUBLIC_KEY — includes ML-KEM key when available ──────── */
      case 'GET_PUBLIC_KEY': {
        const id = await KS.getOrCreateIdentity();
        return { publicKeyB64:id.publicKeyB64, fingerprint:id.fingerprint, mlkemPkB64:id.mlkemPkB64||null, pqcEnabled:!!id.mlkemPkB64 };
      }

      case 'UPGRADE_TO_PQC': {
        return KS.upgradeIdentityToPqc();
      }

      case 'RESET_IDENTITY': {
        await KS.deleteIdentity();
        const id = await KS.getOrCreateIdentity();
        return { success:true, publicKeyB64:id.publicKeyB64, fingerprint:id.fingerprint, pqcEnabled:!!id.mlkemPkB64 };
      }

      /* ── Contact ops ────────────────────────────────────────────────── */
      case 'SAVE_CONTACT': {
        const { handle, platform, publicKeyB64, publicArmor, displayName, mlkemPkB64 } = msg;
        if (!handle || !platform) return { error: 'handle and platform required' };

        let record = { handle, platform, displayName, source: 'native', publicKeyB64, mlkemPkB64: mlkemPkB64 || null };

        // GPG armor path
        if (publicArmor && E.isGpgArmor(publicArmor)) {
          const gpg = await E.parseGpgPublicKey(publicArmor);
          if (gpg.error && !gpg.type) return { error: gpg.error };
          record = { ...record, source: 'gpg', publicArmor,
            publicKeyB64: gpg.publicKeyB64 || null,
            curve: gpg.curve || null,
            fingerprint: gpg.fingerprint || null,
            uid: gpg.uid || null };
          if (gpg.error) record.gpgNote = gpg.error;
        } else if (publicKeyB64) {
          // Validate native key
          try {
            await E.importPublicKey(publicKeyB64);
            const fp = await E.keyFingerprint(publicKeyB64);
            record.fingerprint = fp;
          } catch (_) { return { error: 'Invalid public key — expected base64 SPKI or PGP armor' }; }
        } else {
          return { error: 'Provide a publicKeyB64 or GPG armored key' };
        }

        const saved = await KS.saveContact(record);

        // Notify all open tabs so they can re-try any "no key" overlays
        broadcastContactsUpdated();

        return { success: true, contact: saved };
      }

      case 'LIST_CONTACTS':
        return { contacts: await KS.listContacts() };

      case 'DELETE_CONTACT': {
        await KS.deleteContact(msg.handle, msg.platform);
        broadcastContactsUpdated();
        return { success: true };
      }

      case 'VERIFY_CONTACT': {
        await KS.verifyContact(msg.handle, msg.platform);
        return { success: true };
      }

      case 'RESOLVE_GROUP_RECIPIENTS': {
        const resolved = await KS.resolveGroupRecipients(msg.handles);
        return { resolved };
      }

      /* ── Export encrypted backup ────────────────────────────────────── */
      case 'EXPORT_BACKUP': {
        const { passphrase } = msg;
        if (!passphrase || passphrase.length < 6) {
          return { error: 'Passphrase must be at least 6 characters' };
        }

        const id       = await KS.getOrCreateIdentity();
        const contacts = await KS.listContacts();

        // The private key must be protected — encrypt it with a
        // passphrase-derived AES-GCM key via PBKDF2.
        const salt      = crypto.getRandomValues(new Uint8Array(16));
        const iv        = crypto.getRandomValues(new Uint8Array(12));
        const passKey   = await derivePassKey(passphrase, salt);

        // We encrypt only the private key material
        const rawIdentity = (await chrome.storage.local.get('cc_identity_v2'))['cc_identity_v2'];
        const privatePt = E.str2buf(JSON.stringify({
          privateKeyB64: rawIdentity.privateKeyB64,
          mlkemSkB64:    rawIdentity.mlkemSkB64 || null,
        }));
        const privateCt = await crypto.subtle.encrypt({ name: 'AES-GCM', iv }, passKey, privatePt);

        const backup = {
          version:        3,
          createdAt:      Date.now(),
          publicKeyB64:   id.publicKeyB64,
          fingerprint:    id.fingerprint,
          mlkemPkB64:     id.mlkemPkB64 || null,
          pqcEnabled:     !!id.mlkemPkB64,
          // Encrypted private key(s)
          salt:           E.buf2b64(salt.buffer),
          iv:             E.buf2b64(iv.buffer),
          encPrivateKey:  E.buf2b64(privateCt),
          // Contacts stored in the clear (all public key material)
          contacts:       contacts.map(c => ({
            handle:       c.handle,
            platform:     c.platform,
            displayName:  c.displayName,
            publicKeyB64: c.publicKeyB64,
            publicArmor:  c.publicArmor  || null,
            source:       c.source       || 'native',
            curve:        c.curve        || null,
            fingerprint:  c.fingerprint  || null,
            uid:          c.uid          || null,
            verified:     c.verified     || false,
            addedAt:      c.addedAt      || Date.now(),
          })),
        };

        return { success: true, backup: JSON.stringify(backup, null, 2) };
      }

      /* ── Import encrypted backup ────────────────────────────────────── */
      case 'IMPORT_BACKUP': {
        const { backupJson, passphrase, mode } = msg;
        // mode: 'merge' (keep existing, add new) | 'replace' (wipe and restore)

        let backup;
        try {
          backup = JSON.parse(backupJson);
        } catch (_) {
          return { error: 'Invalid backup file — could not parse JSON' };
        }

        if (!backup.version || !backup.encPrivateKey || !backup.publicKeyB64) {
          return { error: 'Invalid backup format — missing required fields' };
        }

        if (!passphrase) return { error: 'Passphrase required' };

        // Derive key and decrypt private key
        let privateKeyB64;
        try {
          const salt    = new Uint8Array(E.b642buf(backup.salt));
          const iv      = new Uint8Array(E.b642buf(backup.iv));
          const passKey = await derivePassKey(passphrase, salt);
          const plainBuf = await crypto.subtle.decrypt(
            { name: 'AES-GCM', iv },
            passKey,
            E.b642buf(backup.encPrivateKey)
          );
          const plain = JSON.parse(E.buf2str(plainBuf));
          privateKeyB64 = plain.privateKeyB64;
          mlkemSkB64    = plain.mlkemSkB64 || null;
        } catch (_) {
          return { error: 'Wrong passphrase or corrupted backup' };
        }

        // Validate the keypair actually works together
        try {
          await E.importPublicKey(backup.publicKeyB64);
          await E.importPrivateKey(privateKeyB64);
        } catch (_) {
          return { error: 'Backup contains invalid key material' };
        }

        if (mode === 'replace') {
          // Wipe existing identity and contacts
          await KS.deleteIdentity();
          await new Promise(r => chrome.storage.local.remove('cc_contacts_v2', r));
        }

        // Restore identity
        const fp = await E.keyFingerprint(backup.publicKeyB64);
        await new Promise(r => chrome.storage.local.set({
          cc_identity_v2: {
            publicKeyB64:  backup.publicKeyB64,
            privateKeyB64: privateKeyB64,
            fingerprint:   fp,
          }
        }, r));

        // Restore contacts (merge or replace)
        const existingContacts = mode === 'replace' ? [] : await KS.listContacts();
        let added = 0, skipped = 0;

        for (const c of (backup.contacts || [])) {
          const exists = existingContacts.find(
            e => e.handle === c.handle && e.platform === c.platform
          );
          if (exists && mode === 'merge') {
            skipped++;
            continue;
          }
          await KS.saveContact(c);
          added++;
        }

        return {
          success:      true,
          contactsAdded: added,
          contactsSkipped: skipped,
          fingerprint:  fp,
        };
      }

      default:
        return { error: `Unknown message type: ${msg.type}` };
    }
  }

  // Broadcast to all supported-platform tabs so content scripts re-scan
  function broadcastContactsUpdated() {
    const HOSTS = [
      'discord.com', 'app.slack.com', 'web.whatsapp.com', 'web.telegram.org',
      'www.instagram.com', 'x.com', 'twitter.com', 'www.facebook.com', 'messenger.com'
    ];
    chrome.tabs.query({}, tabs => {
      for (const tab of tabs) {
        try {
          const url = new URL(tab.url || '');
          if (HOSTS.some(h => url.hostname.includes(h))) {
            chrome.tabs.sendMessage(tab.id, { type: 'CONTACTS_UPDATED' }).catch(() => {});
          }
        } catch (_) {}
      }
    });
  }

  // PBKDF2 → AES-256-GCM key from a passphrase + salt
  async function derivePassKey(passphrase, salt) {
    const enc      = new TextEncoder();
    const keyMat   = await crypto.subtle.importKey(
      'raw', enc.encode(passphrase), 'PBKDF2', false, ['deriveKey']
    );
    return crypto.subtle.deriveKey(
      { name: 'PBKDF2', salt, iterations: 310000, hash: 'SHA-256' },
      keyMat,
      { name: 'AES-GCM', length: 256 },
      false,
      ['encrypt', 'decrypt']
    );
  }

})(); // end background handler IIFE
